import assert from 'node:assert/strict';
import { ensureSchema } from './src/schema.mjs';
import { createAccounts, getAccounts, updateAccounts, deleteAccounts } from './src/accounts.mjs';

const calls = [];
const rows = new Map();
const client = {
  async query(sql, values = []) {
    calls.push({ sql, values });
    if (sql.includes('CREATE TABLE') || sql.startsWith('ALTER TABLE')) return { rows: [] };
    if (sql.startsWith('INSERT INTO accounts')) {
      const [account_id, name, tier, status, risk_score, created_at] = values;
      const row = { account_id, name, tier, status, risk_score: risk_score ?? null, created_at };
      rows.set(account_id, row);
      return { rows: [row] };
    }
    if (sql.startsWith('SELECT * FROM accounts')) {
      const row = rows.get(values[0]);
      return { rows: row ? [row] : [] };
    }
    if (sql.startsWith('UPDATE accounts SET')) {
      const row = rows.get(values.at(-1));
      let i = 0;
      if (sql.includes('name =')) row.name = values[i++];
      if (sql.includes('tier =')) row.tier = values[i++];
      if (sql.includes('status =')) row.status = values[i++];
      if (sql.includes('risk_score =')) row.risk_score = values[i++];
      return { rows: [] };
    }
    if (sql.startsWith('DELETE FROM accounts')) return { rowCount: rows.delete(values[0]) ? 1 : 0 };
    throw new Error("'`unexpected SQL: ${sql}`);
  },
};

await ensureSchema(client);
assert.match(calls[0].sql, /risk_score'"\\s+INTEGER\\s+CHECK \\(risk_score BETWEEN 0 AND 100\\)/);
assert.match(calls[1].sql, /ADD COLUMN IF NOT EXISTS risk_score INTEGER CHECK \\(risk_score BETWEEN 0 AND 100\\)/);

const base = await createAccounts(client, { accountId: 'base', name: 'Base', tier: 'standard', status: 'active' });
assert.equal(base.riskScore, null);
assert.equal((await updateAccounts(client, 'base', { name: 'Renamed' })).name, 'Renamed');
assert.equal(await deleteAccounts(client, 'base'), true);

const risk = await createAccounts(client, { accountId: 'risk', name: 'Risk', tier: 'midmarket', status: 'at-risk', riskScore: 75 });
assert.equal(risk.riskScore, 75);
assert.equal((await getAccounts(client, 'risk')).riskScore, 75);
assert.equal((await updateAccounts(client, 'risk', { riskScore: 90 })).riskScore, 90);
assert.equal(rows.get('risk').risk_score, 90);
assert.equal(await deleteAccounts(client, 'risk'), true);

const insert = calls.find(({ sql, values }) => sql.startsWith('INSERT INTO accounts') && values[0] === 'risk');
assert.match(insert.sql, /risk_score/);
assert.equal(insert.values[4], 75);
console.log('Local query-contract check passed');
NODE"

